import jax, jax.numpy as jnp, flax.linen as nn
from jax import random

class RegNet(nn.Module):
    @nn.compact
    def __call__(self, x, training: bool):
        x = nn.Dense(128)(x)
        x = nn.BatchNorm(use_running_average=not training)(x)
        x = nn.relu(x)
        x = nn.Dropout(rate=0.3, deterministic=not training)(x)
        return nn.Dense(10)(x)

def loss_fn(params, batch_stats, x, y, key, wd=1e-4):
    (logits, updates), mutables = model.apply(
        {'params': params, 'batch_stats': batch_stats},
        x, training=True,
        rngs={'dropout': key},
        mutable=['batch_stats']
    )
    l2 = sum(jnp.sum(p**2) for p in jax.tree_util.tree_leaves(params))
    return jnp.mean(optax.softmax_cross_entropy(logits, y)) + wd * l2, mutables

