from functools import partial

@jax.jit
def confusion_matrix(y_true, y_pred, num_classes):
    return jnp.zeros((num_classes, num_classes)).at[y_true, y_pred].add(1)

@jax.jit
def precision_recall_f1(cm):
    tp = jnp.diag(cm)
    fp = cm.sum(axis=0) - tp
    fn = cm.sum(axis=1) - tp
    p = tp / (tp + fp + 1e-8)
    r = tp / (tp + fn + 1e-8)
    f1 = 2 * p * r / (p + r + 1e-8)
    return p, r, f1

def kfold_eval(X, y, model_fn, k=5):
    n = X.shape[0]
    def eval_fold(fold_id):
        mask = jnp.arange(n) % k == fold_id
        X_val, y_val = X[mask], y[mask]
        X_tr, y_tr = X[~mask], y[~mask]
        preds = model_fn(X_tr, y_tr, X_val)
        return jnp.mean(preds == y_val)
    return jax.vmap(eval_fold)(jnp.arange(k))

import jax, jax.numpy as jnp, numpy as np
from sklearn.base import BaseEstimator, ClassifierMixin
from sklearn.pipeline import Pipeline
from sklearn.preprocessing import StandardScaler
from sklearn.model_selection import cross_val_score

class JAXLogisticRegressor(BaseEstimator, ClassifierMixin):
    def __init__(self, lr=0.1, epochs=200):
        self.lr, self.epochs = lr, epochs
    def fit(self, X, y):
        X, y = jnp.array(X), jnp.array(y, float)
        p = jnp.zeros(X.shape[1] + 1)
        loss = lambda p: jnp.mean(jnp.log(1 + jnp.exp(-(2*y-1)*(X @ p[:-1] + p[-1]))))
        grad_fn = jax.jit(jax.grad(loss))
        for _ in range(self.epochs):
            p -= self.lr * grad_fn(p)
        self.w_, self.b_ = p[:-1], p[-1]; return self
    def predict(self, X):
        return np.array(jax.nn.sigmoid(jnp.array(X) @ self.w_ + self.b_) > 0.5, int)

pipe = Pipeline([("scale", StandardScaler()), ("clf", JAXLogisticRegressor())])
print(cross_val_score(pipe, X, y, cv=5).mean())

