import jax, jax.numpy as jnp, keras, optax

class L2Dense(keras.Layer):
    def call(self, x):
        x = keras.layers.Dense(64)(x)
        return x / (jnp.linalg.norm(x, axis=-1, keepdims=True) + 1e-8)

inputs = keras.Input(shape=(128,))
x = L2Dense()(inputs)
outputs = keras.layers.Dense(10, activation="softmax")(x)
model = keras.Model(inputs, outputs)

opt = optax.adam(1e-3)
opt_state = opt.init(model.trainable_variables)

@jax.jit
def train_step(tvars, non_tvars, opt_state, x, y):
    def loss_fn(tvars):
        (preds,), non_tvars_out, _ = model.stateless_call(tvars, non_tvars, x)
        return keras.losses.sparse_categorical_crossentropy(y, preds).mean(), non_tvars_out
    (loss, non_tvars_out), grads = jax.value_and_grad(loss_fn, has_aux=True)(tvars)
    updates, opt_state_new = opt.update(grads, opt_state)
    return loss, optax.apply_updates(tvars, updates), non_tvars_out, opt_state_new
